method.custom:
${native-array-type} *val;
g_return_val_if_fail(value != NULL, NULL);
val = (${native-array-type} *)i_cal_object_get_native((ICalObject *)value);
if (val == NULL)
    return NULL;
return ${binding-prefix}_new_full(${native-prefix}_new_${native-suffix}_list(${native-array-type}_clone(val)), NULL);

${native-array-type} *val;
g_return_val_if_fail(self != NULL, NULL);
val = ${native-prefix}_get_${native-suffix}((${native-prefix} *)i_cal_object_get_native((ICalObject *)self));
if (val == NULL)
    return NULL;
return i_cal_enum_array_new_full(${native-array-type}_clone(val), NULL);

${native-elem-type} elem = { 0, };
g_return_if_fail(self != NULL);
elem.val = value;
elem.xvalue = x_value;
${native-prefix}_add_${native-suffix}((${native-type} *)i_cal_object_get_native((ICalObject *)self), &elem);

${native-elem-type} elem = { 0, };
g_return_if_fail(self != NULL);
elem.val = value;
elem.xvalue = x_value;
${native-prefix}_remove_${native-suffix}((${native-type} *)i_cal_object_get_native((ICalObject *)self), &elem);

${native-array-type} *val;
g_return_val_if_fail(value != NULL, NULL);
val = (${native-array-type} *)i_cal_object_get_native((ICalObject *)value);
if (val == NULL)
    return NULL;
return ${binding-prefix}_new_full(${native-prefix}_new_${native-suffix}_list(${native-array-type}_clone(val)), NULL);

${native-array-type} *val;
g_return_val_if_fail(self != NULL, NULL);
val = ${native-prefix}_get_${native-suffix}((${native-type} *)i_cal_object_get_native((ICalObject *)self));
if (val == NULL)
    return NULL;
return i_cal_str_array_new_full(${native-array-type}_clone(val), NULL);
